// Copyright 2019 Aleksander Woźniak
// SPDX-License-Identifier: Apache-2.0

import 'dart:collection';

import 'package:flutter/material.dart';
import 'package:intl/intl.dart';
import 'package:table_calendar/table_calendar.dart';

import 'package:task_manager_flutter/data/utils/_utils.dart';

import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

class LocalizacaoWidget extends StatefulWidget {
  final Function(Pais?, Estado?, Cidade?) onSaved;
  final bool required;

  const LocalizacaoWidget({
    Key? key,
    required this.onSaved,
    this.required = false,
  }) : super(key: key);

  @override
  _LocalizacaoWidgetState createState() => _LocalizacaoWidgetState();
}

class _LocalizacaoWidgetState extends State<LocalizacaoWidget> {
  Pais? selectedPais;
  Estado? selectedEstado;
  Cidade? selectedCidade;
  
  List<Pais> paises = [];
  List<Estado> estados = [];
  List<Cidade> cidades = [];

  final String baseUrl = "http://sua-api.com";

  @override
  void initState() {
    super.initState();
    fetchPaises();
  }

  Future<void> fetchPaises() async {
    final response = await http.get(Uri.parse('$baseUrl/api/paises'));
    if (response.statusCode == 200) {
      setState(() {
        paises = List<Pais>.from(json.decode(response.body).map((x) => Pais.fromJson(x)));
      });
    }
  }

  Future<void> fetchEstados(String? paisId) async {
    if (paisId == null) return;
    
    final response = await http.get(Uri.parse('$baseUrl/api/estados/by-pais/$paisId'));
    if (response.statusCode == 200) {
      setState(() {
        estados = List<Estado>.from(json.decode(response.body).map((x) => Estado.fromJson(x)));
        selectedEstado = null;
        selectedCidade = null;
      });
    }
  }

  Future<void> fetchCidades(String? estadoId) async {
    if (estadoId == null) return;
    
    final response = await http.get(Uri.parse('$baseUrl/api/cidades/by-estado/$estadoId'));
    if (response.statusCode == 200) {
      setState(() {
        cidades = List<Cidade>.from(json.decode(response.body).map((x) => Cidade.fromJson(x));
        selectedCidade = null;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        DropdownButtonFormField<Pais>(
          decoration: InputDecoration(
            labelText: 'País',
            border: OutlineInputBorder(),
          ),
          value: selectedPais,
          items: paises
              .map((pais) => DropdownMenuItem<Pais>(
                    value: pais,
                    child: Text(pais.nomePt),
                  ))
              .toList(),
          onChanged: (Pais? newValue) {
            setState(() {
              selectedPais = newValue;
              estados = [];
              cidades = [];
              selectedEstado = null;
              selectedCidade = null;
            });
            if (newValue != null) {
              fetchEstados(newValue.id.toString());
            }
          },
          validator: (value) => widget.required && value == null ? 'Selecione um país' : null,
        ),
        SizedBox(height: 16),
        DropdownButtonFormField<Estado>(
          decoration: InputDecoration(
            labelText: 'Estado',
            border: OutlineInputBorder(),
          ),
          value: selectedEstado,
          items: estados
              .map((estado) => DropdownMenuItem<Estado>(
                    value: estado,
                    child: Text('${estado.nome} (${estado.uf})'),
                  ))
              .toList(),
          onChanged: (Estado? newValue) {
            setState(() {
              selectedEstado = newValue;
              cidades = [];
              selectedCidade = null;
            });
            if (newValue != null) {
              fetchCidades(newValue.id.toString());
            }
          },
          validator: (value) => widget.required && value == null ? 'Selecione um estado' : null,
        ),
        SizedBox(height: 16),
        DropdownButtonFormField<Cidade>(
          decoration: InputDecoration(
            labelText: 'Cidade',
            border: OutlineInputBorder(),
          ),
          value: selectedCidade,
          items: cidades
              .map((cidade) => DropdownMenuItem<Cidade>(
                    value: cidade,
                    child: Text(cidade.nome),
                  ))
              .toList(),
          onChanged: (Cidade? newValue) {
            setState(() {
              selectedCidade = newValue;
            });
          },
          validator: (value) => widget.required && value == null ? 'Selecione uma cidade' : null,
        ),
      ],
    );
  }
}

// Model classes
class Pais {
  final int id;
  final String nome;
  final String nomePt;
  final String iso2;
  final String iso3;
  final int bacen;

  Pais({
    required this.id,
    required this.nome,
    required this.nomePt,
    required this.iso2,
    required this.iso3,
    required this.bacen,
  });

  factory Pais.fromJson(Map<String, dynamic> json) {
    return Pais(
      id: json['id'],
      nome: json['nome'],
      nomePt: json['nome_pt'],
      iso2: json['iso2'],
      iso3: json['iso3'],
      bacen: json['bacen'],
    );
  }
}

class Estado {
  final int id;
  final String nome;
  final String uf;
  final int ibge;
  final int pais;

  Estado({
    required this.id,
    required this.nome,
    required this.uf,
    required this.ibge,
    required this.pais,
  });

  factory Estado.fromJson(Map<String, dynamic> json) {
    return Estado(
      id: json['id'],
      nome: json['nome'],
      uf: json['uf'],
      ibge: json['ibge'],
      pais: json['pais'],
    );
  }
}

class Cidade {
  final int id;
  final String nome;
  final int uf;
  final int ibge;
  final String latLon;

  Cidade({
    required this.id,
    required this.nome,
    required this.uf,
    required this.ibge,
    required this.latLon,
  });

  factory Cidade.fromJson(Map<String, dynamic> json) {
    return Cidade(
      id: json['id'],
      nome: json['nome'],
      uf: json['uf'],
      ibge: json['ibge'],
      latLon: json['lat_lon'],
    );
  }
}
